INSERT INTO t_p30913071_project_cool_idea.shop_products (category, title, description, price, image_url, tags, sort_order) VALUES
-- Окна
('windows', 'Одностворчатое окно', 'Классическое одностворчатое окно с поворотно-откидным механизмом. Профиль 70 мм, двухкамерный стеклопакет.', 'от 8 500 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/7908776c-0e57-4e8f-999e-74eb427d0ac9.jpg', 'Хит продаж', 1),
('windows', 'Двустворчатое окно', 'Двустворчатое окно — одна створка глухая, вторая поворотно-откидная. Отличное соотношение цена/качество.', 'от 13 500 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/0f91fa6d-0bf9-4a49-9087-8b2132a29895.jpg', '', 2),
('windows', 'Трёхстворчатое окно', 'Панорамное трёхстворчатое окно. Две активные створки, средняя — глухая. Максимум света в комнате.', 'от 21 000 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/c4f5db69-63e0-4e81-b222-8140dcfe31de.jpg', '', 3),
('windows', 'Балконный блок', 'Окно + дверь балконная. Полный комплект с монтажом, отливами и откосами.', 'от 19 000 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/ba668690-ead8-4bbc-a435-311bb87d7d2a.jpg', 'Комплект', 4),
('windows', 'Алюминиевое окно', 'Алюминиевый профиль — для коммерческих помещений, витрин, фасадов. Повышенная прочность.', 'от 16 000 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/cfcfb5a0-c1fc-4154-aa6f-e2adf9befb41.jpg', '', 5),
('windows', 'Нестандартный размер', 'Окна любой формы и размера — трапеции, арки, круглые. Изготовление по индивидуальным чертежам.', 'по запросу', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/07695eb3-4f15-4141-998b-5adafc793700.jpg', 'Под заказ', 6),
-- Двери
('doors', 'Входная металлическая дверь', 'Стальная дверь 2 мм, три контура уплотнения, замок 3 класса защиты. Тёплая, тихая, надёжная.', 'от 18 000 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/d3cbf08d-62cb-436b-9750-55c962e58322.jpg', 'Популярное', 1),
('doors', 'Входная дверь с терморазрывом', 'Дверь с терморазрывом — не промерзает, не покрывается инеем. Идеально для частного дома.', 'от 28 000 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/4ef5191c-9282-41e3-9e5a-694edf313396.jpg', 'Для дома', 2),
('doors', 'Межкомнатная дверь МДФ', 'Гладкое полотно МДФ с ПВХ-покрытием. Лёгкая, доступная, широкая палитра цветов.', 'от 6 500 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/017ce7fb-904d-41e3-9324-f5564b71e7c5.jpg', '', 3),
('doors', 'Межкомнатная дверь со стеклом', 'Дверное полотно со вставкой из закалённого стекла. Современный дизайн, больше света в помещении.', 'от 9 000 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/5e31b78f-5671-4ad3-9fe3-876de937519c.jpg', '', 4),
('doors', 'Раздвижная дверь-купе', 'Экономия пространства — дверь уходит в стену или в сторону. Подходит для небольших квартир.', 'от 12 000 ₽', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/d05d381c-d3e6-4fc7-95c5-4897d62b8518.jpg', '', 5),
('doors', 'Дверь под заказ', 'Нестандартные размеры, материалы и отделка. Изготовление по вашему проекту и пожеланиям.', 'по запросу', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/4beecf2a-97de-4da4-b777-90b2c7b2c3b1.jpg', 'Под заказ', 6),
-- 3D Забор
('fence', '3D панель 1530×2500 мм', 'Стандартная панель высотой 1,53 м. Проволока 4 мм, оцинковка + полимерное покрытие. Самый популярный вариант.', 'от 850 ₽/панель', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/c7815602-6840-4b20-877f-64ca1d6f29b6.jpg', 'Хит', 1),
('fence', '3D панель 2030×2500 мм', 'Панель высотой 2,03 м — для повышенной приватности. Надёжное ограждение для частного дома.', 'от 1 100 ₽/панель', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/c618dadb-b048-4f40-8311-1851a3842570.jpg', '', 2),
('fence', '3D панель 2530×2500 мм', 'Высокая панель 2,53 м — максимальная защита и приватность. Для промышленных объектов и предприятий.', 'от 1 400 ₽/панель', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/1c0a6674-40b6-4b01-bd3c-507a36d15fd9.jpg', '', 3),
('fence', 'Столбы и комплектующие', 'Столбы квадратные 60×60 мм и 60×40 мм, крепёжные скобы, заглушки. Всё для монтажа забора.', 'от 350 ₽/шт', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/b0250445-b78a-4978-95e4-8abca1fb2533.jpg', '', 4),
('fence', 'Монтаж забора под ключ', 'Установка 3D-забора: разметка, бурение, бетонирование столбов, крепление панелей. Сдача за 1 день.', 'от 900 ₽/м.п.', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/9ada2b6f-6d6a-4fae-9b78-5768c80b081c.jpg', 'Под ключ', 5),
('fence', 'Калитки и ворота', 'Распашные и откатные ворота из 3D-сетки. Калитки в комплект. Цвет в тон забору.', 'по запросу', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/94ebd2f9-15b8-4aef-b4d3-d6d01dbbe994.jpg', '', 6),
-- Сыпучие смеси
('mixtures', 'Цемент М500 (50 кг)', 'Портландцемент М500 Д0 — универсальный, для фундаментов, стяжек, кладки. Высокая прочность.', 'от 420 ₽/мешок', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/5739fc2d-0faa-4248-9ce9-ef512f4b65aa.jpg', 'Хит', 1),
('mixtures', 'Речной песок (тонна)', 'Чистый речной песок, промытый. Для кладки, штукатурки, бетона, засыпки. Доставка самосвалом.', 'от 1 800 ₽/т', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/56330a81-5a2a-4d7d-84c6-e36666777faf.jpg', '', 2),
('mixtures', 'Щебень фр. 20–40 (тонна)', 'Гранитный щебень фракции 20–40 мм. Для фундаментов, дренажа, дорожных работ.', 'от 2 200 ₽/т', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/bb866926-fa94-4bfd-a499-529e349461ab.jpg', '', 3),
('mixtures', 'Штукатурная смесь (30 кг)', 'Цементно-песчаная штукатурная смесь для внутренних и наружных работ. Без усадки и трещин.', 'от 340 ₽/мешок', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/f4e9e8e5-c489-47a7-8c03-b6be9e4ac272.jpg', '', 4),
('mixtures', 'Керамзит (мешок 50 л)', 'Лёгкий керамзит фракции 10–20 мм. Для утепления полов, кровли, засыпки пустот.', 'от 280 ₽/мешок', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/06f08f2c-b1f3-40ae-8e12-b372c55590a9.jpg', '', 5),
('mixtures', 'Кладочная смесь (25 кг)', 'Готовая смесь для кладки кирпича, блоков, камня. Морозостойкая, влагостойкая.', 'от 290 ₽/мешок', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/5fd6dcc9-f7dd-47de-836e-30689ee81afa.jpg', '', 6),
-- Бетон
('concrete', 'Бетон М100 (B7.5)', 'Подготовительный бетон для подбетонки, выравнивающих слоёв, оснований под фундамент.', 'от 4 200 ₽/м³', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/5208bf0c-a3ce-4f0b-a670-d95f89df95f8.jpg', '', 1),
('concrete', 'Бетон М200 (B15)', 'Универсальный бетон для стяжек, отмосток, дорожек, лёгких фундаментов и монолитных конструкций.', 'от 5 100 ₽/м³', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/e58cb71d-d040-4c50-86e4-fca07d98424f.jpg', 'Популярный', 2),
('concrete', 'Бетон М300 (B22.5)', 'Для ленточных и плитных фундаментов, перекрытий, колонн. Высокая прочность и долговечность.', 'от 5 800 ₽/м³', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/d1234c63-408d-4d91-a18c-7e6d6e358afd.jpg', 'Хит', 3),
('concrete', 'Бетон М350 (B25)', 'Для ответственных конструкций — монолитные дома, бассейны, подземные сооружения.', 'от 6 300 ₽/м³', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/25610605-042c-4d2b-87c8-2e16a3b8878d.jpg', '', 4),
('concrete', 'Бетон М400 (B30)', 'Высокопрочный бетон для гидротехнических сооружений, мостов, промышленных объектов.', 'от 7 100 ₽/м³', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/c8349829-b049-49a7-8690-d54fd847a5a5.jpg', '', 5),
('concrete', 'Срочная доставка бетона', 'Доставка бетона любой марки в течение 2 часов после заявки. Без выходных, по всей Ялте.', 'по запросу', 'https://cdn.poehali.dev/projects/7f03272f-bca4-46b6-9dc3-4ea2338fe786/files/553e10d2-c993-479a-8efb-d42cf3cb6709.jpg', 'Срочно', 6);
